import{c as i,Q as s,j as a,m as n}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Skill Issue: Harness Engineering for Coding Agents","description":"","frontmatter":{"title":"Skill Issue: Harness Engineering for Coding Agents","author":"Human Layer","date":"2026-04-30T00:00:00.000Z","source":"https://www.humanlayer.dev/blog/skill-issue-harness-engineering-for-coding-agents","tags":["agent-harness","research"]},"headers":[],"relativePath":"research/agent-harness/references/2026-04-30-skill-issue-harness-engineering-humanlayer.md","filePath":"research/agent-harness/references/2026-04-30-skill-issue-harness-engineering-humanlayer.md","lastUpdated":1779894392000}'),t={name:"research/agent-harness/references/2026-04-30-skill-issue-harness-engineering-humanlayer.md"};function r(o,e,l,c,d,u){return s(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="skill-issue-harness-engineering-for-coding-agents" tabindex="-1">Skill Issue: Harness Engineering for Coding Agents <a class="header-anchor" href="#skill-issue-harness-engineering-for-coding-agents" aria-label="Permalink to &quot;Skill Issue: Harness Engineering for Coding Agents&quot;">​</a></h1><h2 id="core-thesis" tabindex="-1">Core Thesis <a class="header-anchor" href="#core-thesis" aria-label="Permalink to &quot;Core Thesis&quot;">​</a></h2><p>Rather than waiting for superior AI models to solve coding agent failures, teams should focus on <strong>harness engineering</strong>—optimizing the configuration and runtime environment surrounding the model to dramatically improve performance and reliability.</p><h2 id="key-definition" tabindex="-1">Key Definition <a class="header-anchor" href="#key-definition" aria-label="Permalink to &quot;Key Definition&quot;">​</a></h2><p><strong>Harness Engineering</strong>: The practice of systematically addressing agent mistakes through deliberate configuration adjustments. As Mitchell Hashimoto framed it, it means taking &quot;time to engineer a solution such that the agent never makes that mistake again.&quot;</p><p>The article presents harness engineering as a subset of context engineering, addressing:</p><ul><li>Capability expansion</li><li>Codebase-specific knowledge injection</li><li>Deterministic behavior beyond prompts</li><li>Task success rate improvement</li><li>Context window efficiency</li></ul><h2 id="primary-configuration-levers" tabindex="-1">Primary Configuration Levers <a class="header-anchor" href="#primary-configuration-levers" aria-label="Permalink to &quot;Primary Configuration Levers&quot;">​</a></h2><h3 id="_1-claude-md-agents-md-files" tabindex="-1">1. <strong>CLAUDE.md/AGENTS.md Files</strong> <a class="header-anchor" href="#_1-claude-md-agents-md-files" aria-label="Permalink to &quot;1. **CLAUDE.md/AGENTS.md Files**&quot;">​</a></h3><p>Markdown files injected deterministically into system prompts. Keep them under 60 lines, concise, universally applicable, and avoid auto-generation.</p><h3 id="_2-mcp-servers" tabindex="-1">2. <strong>MCP Servers</strong> <a class="header-anchor" href="#_2-mcp-servers" aria-label="Permalink to &quot;2. **MCP Servers**&quot;">​</a></h3><p>Primary purpose: extending capabilities with tools. Cautions include:</p><ul><li>Tool descriptions consume context budget</li><li>Limit to actively-used servers</li><li>Prefer CLI tools when models already understand them</li><li>Never connect to untrusted servers (prompt injection risk)</li></ul><h3 id="_3-skills" tabindex="-1">3. <strong>Skills</strong> <a class="header-anchor" href="#_3-skills" aria-label="Permalink to &quot;3. **Skills**&quot;">​</a></h3><p>Enable <strong>progressive disclosure</strong>—agents access knowledge only when needed. Bundle related instructions, knowledge files, and tools within skill directories for selective activation.</p><h3 id="_4-sub-agents" tabindex="-1">4. <strong>Sub-Agents</strong> <a class="header-anchor" href="#_4-sub-agents" aria-label="Permalink to &quot;4. **Sub-Agents**&quot;">​</a></h3><p>Provide <strong>context firewall functionality</strong>:</p><ul><li>Isolate discrete tasks in separate context windows</li><li>Prevent intermediate noise accumulation</li><li>Maintain coherency across many sessions</li><li>Support cost optimization (cheaper models for simpler sub-tasks)</li></ul><p>Research validates this: Chroma&#39;s context rot studies show performance degrades at longer context lengths, especially when low semantic similarity exists between questions and context.</p><h3 id="_5-hooks" tabindex="-1">5. <strong>Hooks</strong> <a class="header-anchor" href="#_5-hooks" aria-label="Permalink to &quot;5. **Hooks**&quot;">​</a></h3><p>Automated scripts triggered at lifecycle events:</p><ul><li>Run silently on success</li><li>Surface only errors/actionable feedback</li><li>Control permissions and integrations</li><li>Verify work (typechecks, builds)</li></ul><h2 id="architecture-insight-context-firewall" tabindex="-1">Architecture Insight: Context Firewall <a class="header-anchor" href="#architecture-insight-context-firewall" aria-label="Permalink to &quot;Architecture Insight: Context Firewall&quot;">​</a></h2><p>Sub-agents function as isolated context environments, preventing intermediate tool calls and results from polluting parent sessions. This enables longer problem-solving sequences without degradation.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Parent Agent (orchestration) → Sub-Agent 1 (research) → Condensed result</span></span>
<span class="line"><span>                             → Sub-Agent 2 (implementation) → Condensed result</span></span></code></pre></div><h2 id="back-pressure-mechanisms" tabindex="-1">Back-Pressure Mechanisms <a class="header-anchor" href="#back-pressure-mechanisms" aria-label="Permalink to &quot;Back-Pressure Mechanisms&quot;">​</a></h2><p>Verification systems enable self-checking:</p><ul><li>Typechecks and builds</li><li>Unit/integration tests</li><li>Code coverage</li><li>UI interaction testing</li></ul><p><strong>Critical</strong>: Keep verification output context-efficient—surface only errors, silence on success.</p><h2 id="notable-quote" tabindex="-1">Notable Quote <a class="header-anchor" href="#notable-quote" aria-label="Permalink to &quot;Notable Quote&quot;">​</a></h2><p>&quot;It&#39;s not a model problem. It&#39;s a <strong>configuration problem.</strong>&quot;</p><h2 id="practical-approach" tabindex="-1">Practical Approach <a class="header-anchor" href="#practical-approach" aria-label="Permalink to &quot;Practical Approach&quot;">​</a></h2><ul><li><strong>Start simple</strong>, add configuration only when failures occur</li><li>Optimize iteration speed over single-attempt success</li><li>Distribute battle-tested configs team-wide</li><li>Test ruthlessly and discard ineffective optimizations</li></ul><h2 id="what-didn-t-work" tabindex="-1">What Didn&#39;t Work <a class="header-anchor" href="#what-didn-t-work" aria-label="Permalink to &quot;What Didn&#39;t Work&quot;">​</a></h2><ul><li>Pre-designing ideal configurations</li><li>Installing numerous unused tools</li><li>Running full test suites per session</li><li>Micro-optimizing tool access across sub-agents</li></ul><p>This represents a paradigm shift: agent performance bottlenecks exist primarily in orchestration and context management, not raw model capability.</p>`,36)])])}const p=i(t,[["render",r]]);export{g as __pageData,p as default};
